# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, exceptions as es_exceptions
import os
import re
import threading

app = Flask(__name__)

ES_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ES_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")

_es_client = None
_es_lock = threading.Lock()


def get_es_client():
    global _es_client
    if _es_client is None:
        with _es_lock:
            if _es_client is None:
                _es_client = Elasticsearch(
                    ES_URL,
                    request_timeout=2,
                    max_retries=2,
                    retry_on_timeout=True,
                    timeout=2,
                )
    return _es_client


def sanitize_query(q):
    q = (q or "").strip()
    q = re.sub(r"\s+", " ", q)
    return q[:128]


@app.route("/api/search", methods=["GET"])
def search_products():
    q = sanitize_query(request.args.get("q", ""))

    if not q:
        return jsonify({"error": "Missing required query parameter: q"}), 400

    es = get_es_client()

    body = {
        "size": 20,
        "_source": ["id", "name", "description", "price", "image_url", "category", "sku"],
        "query": {
            "multi_match": {
                "query": q,
                "fields": ["name^4", "description^2", "category^2", "sku"],
                "type": "best_fields",
                "operator": "and",
                "fuzziness": "AUTO"
            }
        },
        "sort": [
            "_score",
            {"popularity": "desc"}
        ]
    }

    try:
        resp = es.search(index=ES_INDEX, body=body)
        hits = resp.get("hits", {}).get("hits", [])
        results = []
        for hit in hits:
            src = hit.get("_source", {})
            src["score"] = hit.get("_score", 0)
            results.append(src)

        return jsonify({
            "query": q,
            "count": len(results),
            "results": results
        }), 200

    except es_exceptions.NotFoundError:
        return jsonify({"error": "Search index not found"}), 503
    except es_exceptions.ConnectionError:
        return jsonify({"error": "Search service unavailable"}), 503
    except es_exceptions.TransportError:
        return jsonify({"error": "Search request failed"}), 502
    except Exception:
        return jsonify({"error": "Internal server error"}), 500


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))